using System;
using System.IO;
using System.Runtime.Serialization.Formatters.Binary;

public class SessionManager
{
    private string sessionId = Guid.NewGuid().ToString();
    private string filePath = $"session_{sessionId}.dat";

    public void SaveSession(object session)
    {
        using (var fileStream = File.Create(filePath))
        {
            var formatter = new BinaryFormatter();
            formatter.Serialize(fileStream, session);
        }
    }

    public object LoadSession()
    {
        if (!File.Exists(filePath)) return null;

        try
        {
            using (var fileStream = File.OpenRead(filePath))
            {
                var formatter = new BinaryFormatter();
                return formatter.Deserialize(fileStream);
            }
        }
        catch (Exception ex)
        {
            Console.WriteLine($"Error loading session: {ex.Message}");
            return null;
        }
    }

    public void DeleteSession()
    {
        if (File.Exists(filePath)) File.Delete(filePath);
    }
}

