    public void AddToCart(Item item)
    {
        if (Cart == null) Cart = new ShoppingCart();
        Cart.AddItem(item);
    }

    public void RemoveFromCart(Item item)
    {
        if (Cart != null) Cart.RemoveItem(item);
    }
